// Generate PORTING.md: every callback the Rust engine must port, grouped and
// checkboxed. Re-run after PS updates; check off items as they are ported.
'use strict';
const fs = require('fs');
const path = require('path');
const { sim, MOD, FORMAT, fnNames, legal } = require('./ps');

const dex = sim.Dex.mod(MOD);

const lines = [
	'# Porting checklist',
	'',
	`Source of truth: PS \`${MOD}\` flattened dex + merged Scripts (format \`${FORMAT}\`).`,
	'Generated by `node tools/gen-porting-checklist.js` — regenerate after PS updates, do not hand-edit the tables.',
	'',
];

let total = 0;
function section(title, entries) {
	const withCb = entries.filter(([, fns]) => fns.length);
	lines.push(`## ${title} (${withCb.length} entries, ${withCb.reduce((a, [, f]) => a + f.length, 0)} callbacks)`, '');
	for (const [id, fns] of withCb.sort((a, b) => a[1].length - b[1].length || (a[0] < b[0] ? -1 : 1))) {
		total += fns.length;
		lines.push(`- [ ] \`${id}\` — ${fns.map(f => `\`${f}\``).join(', ')}`);
	}
	lines.push('');
}

section('Conditions (port first — statuses/weathers/volatiles are core)',
	Object.keys(dex.data.Conditions).map(id => [id, fnNames(dex.data.Conditions[id])]));
section('Moves', dex.moves.all().filter(legal).map(m => [sim.toID(m.name), fnNames(m)]));
section('Items', dex.items.all().filter(legal).map(i => [i.id, fnNames(i)]));

// Engine-level Scripts overrides (gen2 + gen2stadium2 + inherited gen3/4 diffs).
{
	const scripts = dex.data.Scripts;
	const entries = [];
	for (const k in scripts) {
		if (typeof scripts[k] === 'function') entries.push([`Battle.${k}`, ['(override)']]);
		else if (scripts[k] && typeof scripts[k] === 'object') {
			for (const k2 in scripts[k]) {
				if (typeof scripts[k][k2] === 'function') entries.push([`${k}.${k2}`, ['(override)']]);
			}
		}
	}
	lines.push(`## Engine Scripts overrides (${entries.length}) — gen2/stadium2 mechanics replacing base engine paths`, '');
	for (const [id] of entries) lines.push(`- [ ] \`${id}\``);
	lines.push('');
}

// Format rules with runtime hooks.
{
	const format = sim.Dex.formats.get(FORMAT);
	lines.push('## Format rules with runtime behavior', '');
	const ruleTable = sim.Dex.formats.getRuleTable(format);
	for (const [ruleid] of ruleTable) {
		const rule = dex.data.Rulesets[sim.toID(ruleid)];
		if (!rule) continue;
		const fns = fnNames(rule).filter(f => f.startsWith('on'));
		if (fns.length) {
			total += fns.length;
			lines.push(`- [ ] \`${rule.name}\` — ${fns.map(f => `\`${f}\``).join(', ')}`);
		}
	}
	lines.push('');
}

lines.push(`**Total callbacks: ${total}**`, '');
const dest = path.join(__dirname, '..', 'PORTING.md');
fs.writeFileSync(dest, lines.join('\n'));
console.log(`wrote ${dest} (${total} callbacks)`);
